import React, { useState } from "react";
import "./login.css";
import { FaUser, FaLock } from "react-icons/fa";
import { useNavigate } from "react-router-dom";

const Login = ({ setIsAuthenticated }) => {
  const [showPassword, setShowPassword] = useState(false);
  const [email, setEmail] = useState("");
  const [password, setPassword] = useState("");
  const [message, setMessage] = useState("");
  const [mfaRequired, setMfaRequired] = useState(false);
  const [mfaCode, setMfaCode] = useState("");

  const navigate = useNavigate();
  
  const handleLogin = async () => {
    const response = await fetch("http://localhost:5000/api/login", {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({ email, password }),
    });

    const data = await response.json();
    if (data.success && data.mfaRequired) {
      setMfaRequired(true);
      setMessage("MFA code sent to your email.");
    } else if (data.success) {
      localStorage.setItem("authenticated", "true"); // Store authentication
      setIsAuthenticated(true);
      navigate("/");
    } else {
      setMessage(data.message || "Invalid email or password.");
    }
  };

  const verifyMfa = async () => {
    const response = await fetch("http://localhost:5000/api/verify-mfa", {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({ email, code: mfaCode }),
    });

    const data = await response.json();
    if (data.success) {
      localStorage.setItem("authenticated", "true"); // Store authentication
      setIsAuthenticated(true);
      navigate("/");
    } else {
      setMessage(data.message);
      setMfaCode("");
    }
  };

  return (
    <div className="login-container">
      <img src="/assets/logo.png" alt="UAS Logo" className="logo" />
      <div className="login-box">
        <h2>Login</h2>
        

        <div className="input-group">
          <FaUser className="icon" />
          <input
            type="text"
            placeholder="Enter your username/email"
            value={email}
            onChange={(e) => setEmail(e.target.value)}
          />
        </div>

        <div className="input-group">
          <FaLock className="icon" />
          <input
            type="password"
            placeholder="Enter your password"
            value={password}
            onChange={(e) => setPassword(e.target.value)}
          />
        </div>

        {message && <p className="login-message">{message}</p>}

        <button className="login-button" onClick={handleLogin}>
          Login
        </button>
      </div>
    </div>
  );
};

export default Login;
